import{_ as i,o as e,c as l,ak as s}from"./chunks/framework.BZTYhN8l.js";const b=JSON.parse('{"title":"物理层笔记","description":"","frontmatter":{},"headers":[],"relativePath":"计算机网络/物理层和数据链路层/物理层.md","filePath":"计算机网络/物理层和数据链路层/物理层.md","lastUpdated":1775125132000}'),t={name:"计算机网络/物理层和数据链路层/物理层.md"};function h(r,a,n,d,o,c){return e(),l("div",null,[...a[0]||(a[0]=[s(`<h1 id="物理层笔记" tabindex="-1">物理层笔记 <a class="header-anchor" href="#物理层笔记" aria-label="Permalink to “物理层笔记”">​</a></h1><h2 id="一、物理层的位置" tabindex="-1">一、物理层的位置 <a class="header-anchor" href="#一、物理层的位置" aria-label="Permalink to “一、物理层的位置”">​</a></h2><ul><li>物理层位于计算机网络分层体系的<strong>最底层</strong></li><li>上一层是：<strong>数据链路层</strong></li></ul><p>分层结构（自上而下）：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>应用层 → 运输层 → 网络层 → 数据链路层 → 物理层</span></span></code></pre></div><hr><h2 id="二、物理层的核心作用" tabindex="-1">二、物理层的核心作用 <a class="header-anchor" href="#二、物理层的核心作用" aria-label="Permalink to “二、物理层的核心作用”">​</a></h2><p>👉 一句话总结：</p><blockquote><p><strong>解决“用什么信号表示 0 和 1”的问题</strong></p></blockquote><hr><h2 id="三、如何理解-信号表示比特" tabindex="-1">三、如何理解“信号表示比特” <a class="header-anchor" href="#三、如何理解-信号表示比特" aria-label="Permalink to “三、如何理解“信号表示比特””">​</a></h2><h3 id="_1️⃣-数据本质" tabindex="-1">1️⃣ 数据本质 <a class="header-anchor" href="#_1️⃣-数据本质" aria-label="Permalink to “1️⃣ 数据本质”">​</a></h3><ul><li>所有数据本质都是：</li></ul><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>0101（二进制）</span></span></code></pre></div><hr><h3 id="_2️⃣-为什么需要信号" tabindex="-1">2️⃣ 为什么需要信号？ <a class="header-anchor" href="#_2️⃣-为什么需要信号" aria-label="Permalink to “2️⃣ 为什么需要信号？”">​</a></h3><p>👉 因为：</p><ul><li>网络中不能直接传输“0 和 1”</li><li>必须通过物理介质传播</li></ul><hr><h3 id="_3️⃣-信号形式" tabindex="-1">3️⃣ 信号形式 <a class="header-anchor" href="#_3️⃣-信号形式" aria-label="Permalink to “3️⃣ 信号形式”">​</a></h3><p>物理层将比特转换为：</p><ul><li>电信号（网线）</li><li>光信号（光纤）</li><li>电磁波（无线）</li></ul><hr><h2 id="四、物理层的核心工作流程" tabindex="-1">四、物理层的核心工作流程 <a class="header-anchor" href="#四、物理层的核心工作流程" aria-label="Permalink to “四、物理层的核心工作流程”">​</a></h2><h3 id="发送端" tabindex="-1">发送端 <a class="header-anchor" href="#发送端" aria-label="Permalink to “发送端”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>比特流（0101） → 转换为信号（波形） → 在介质中传播</span></span></code></pre></div><p>步骤：</p><ol><li>接收来自数据链路层的数据</li><li>添加物理层信息（协议相关）</li><li>将比特流转换为信号（编码/调制）</li><li>发送到传输介质</li></ol><hr><h3 id="接收端" tabindex="-1">接收端 <a class="header-anchor" href="#接收端" aria-label="Permalink to “接收端”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>信号（波形） → 还原为比特流（0101）</span></span></code></pre></div><p>步骤：</p><ol><li>接收信号</li><li>按协议解析信号</li><li>还原出比特流</li><li>去掉物理层信息</li><li>交给数据链路层</li></ol><hr><h2 id="五、发送与接收的整体流程" tabindex="-1">五、发送与接收的整体流程 <a class="header-anchor" href="#五、发送与接收的整体流程" aria-label="Permalink to “五、发送与接收的整体流程”">​</a></h2><h3 id="发送端-自上而下" tabindex="-1">发送端（自上而下） <a class="header-anchor" href="#发送端-自上而下" aria-label="Permalink to “发送端（自上而下）”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>上层数据 → 数据链路层封装 → 物理层转换为信号 → 发送</span></span></code></pre></div><hr><h3 id="接收端-自下而上" tabindex="-1">接收端（自下而上） <a class="header-anchor" href="#接收端-自下而上" aria-label="Permalink to “接收端（自下而上）”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>接收信号 → 物理层还原比特 → 数据链路层处理 → 上层处理</span></span></code></pre></div><hr><h2 id="六、物理层与数据链路层关系" tabindex="-1">六、物理层与数据链路层关系 <a class="header-anchor" href="#六、物理层与数据链路层关系" aria-label="Permalink to “六、物理层与数据链路层关系”">​</a></h2><ul><li>数据链路层： <ul><li>负责<strong>帧的封装（头 + 尾）</strong></li><li>负责<strong>差错检测</strong></li></ul></li><li>物理层： <ul><li>不关心数据内容</li><li>只负责：</li></ul></li></ul><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>比特流 ↔ 信号</span></span></code></pre></div><hr><h2 id="七、协议的重要性" tabindex="-1">七、协议的重要性 <a class="header-anchor" href="#七、协议的重要性" aria-label="Permalink to “七、协议的重要性”">​</a></h2><p>👉 物理层通信必须满足：</p><blockquote><p><strong>发送端和接收端使用相同协议</strong></p></blockquote><p>否则：</p><ul><li>无法正确解析信号</li><li>无法还原比特</li></ul><hr><h2 id="八、关键理解点" tabindex="-1">八、关键理解点 <a class="header-anchor" href="#八、关键理解点" aria-label="Permalink to “八、关键理解点”">​</a></h2><h3 id="_1️⃣-物理层处理的仍然是二进制" tabindex="-1">1️⃣ 物理层处理的仍然是二进制 <a class="header-anchor" href="#_1️⃣-物理层处理的仍然是二进制" aria-label="Permalink to “1️⃣ 物理层处理的仍然是二进制”">​</a></h3><ul><li>从应用层开始就是 0101</li><li>物理层只是“换表现形式”</li></ul><hr><h3 id="_2️⃣-本质是-映射关系" tabindex="-1">2️⃣ 本质是“映射关系” <a class="header-anchor" href="#_2️⃣-本质是-映射关系" aria-label="Permalink to “2️⃣ 本质是“映射关系””">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>0 / 1 ↔ 某种信号形式</span></span></code></pre></div><hr><h3 id="_3️⃣-物理层不关心内容" tabindex="-1">3️⃣ 物理层不关心内容 <a class="header-anchor" href="#_3️⃣-物理层不关心内容" aria-label="Permalink to “3️⃣ 物理层不关心内容”">​</a></h3><ul><li>不关心： <ul><li>HTTP</li><li>TCP</li><li>IP</li></ul></li><li>只关心： <ul><li>如何传输比特</li></ul></li></ul><hr><h2 id="九、物理层提供的服务" tabindex="-1">九、物理层提供的服务 <a class="header-anchor" href="#九、物理层提供的服务" aria-label="Permalink to “九、物理层提供的服务”">​</a></h2><p>👉 提供：</p><blockquote><p><strong>比特流传输服务</strong></p></blockquote><p>通俗理解：</p><ul><li>把 0101 变成可以在介质上传播的信号</li><li>再把信号还原成 0101</li></ul><hr><h2 id="十、总结" tabindex="-1">十、总结 <a class="header-anchor" href="#十、总结" aria-label="Permalink to “十、总结”">​</a></h2><h3 id="核心流程" tabindex="-1">核心流程 <a class="header-anchor" href="#核心流程" aria-label="Permalink to “核心流程”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>发送端：比特 → 信号  </span></span>
<span class="line"><span>接收端：信号 → 比特</span></span></code></pre></div><hr><h3 id="核心一句话" tabindex="-1">核心一句话 <a class="header-anchor" href="#核心一句话" aria-label="Permalink to “核心一句话”">​</a></h3><blockquote><p><strong>物理层的本质就是实现“比特流在物理介质上的传输”</strong></p></blockquote>`,73)])])}const k=i(t,[["render",h]]);export{b as __pageData,k as default};
